function extractJson(text) {
  if (typeof text !== 'string') return null;
  const match = text.match(/\{[\s\S]*\}/);
  if (!match) return null;
  try {
    return JSON.parse(match[0]);
  } catch {
    return null;
  }
}

function pickRaw(item) {
  // LLM 노드마다 결과 필드명이 달라서 후보를 넓게 잡음
  return (
    item.json.responseText ||
    item.json.text ||
    item.json.outputText ||
    item.json.output ||
    item.json.message ||
    item.json.content ||
    JSON.stringify(item.json)
  );
}

const reviews = [];

for (const item of items) {
  const raw = pickRaw(item);
  const parsed = extractJson(raw) || item.json;

  if (
    parsed &&
    parsed.model !== undefined &&
    parsed.originality !== undefined &&
    parsed.validity !== undefined &&
    parsed.generalizability !== undefined
  ) {
    reviews.push(parsed);
  }
}

// 평균 점수 (0~5)
let total = 0;
let count = 0;

for (const r of reviews) {
  total += Number(r.originality);
  total += Number(r.validity);
  total += Number(r.generalizability);
  count += 3;
}

const finalScore = count ? Number((total / count).toFixed(2)) : null;

// Markdown 표 만들기
const mdHeader =
  `| Model | Originality | Validity | Generalizability | Comment(ko) |\n` +
  `|---|---:|---:|---:|---|`;

const mdRows = reviews.map(r => {
  const c = (r.comment_ko || '').replace(/\n/g, ' ');
  return `| ${r.model} | ${r.originality} | ${r.validity} | ${r.generalizability} | ${c} |`;
});

const table_markdown = [mdHeader, ...mdRows].join('\n');

// HTML 표 만들기
const escapeHtml = (s) =>
  String(s ?? '')
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;')
    .replace(/'/g, '&#039;');

const table_html = `
<table border="1" cellpadding="8" cellspacing="0" style="border-collapse:collapse; width:100%;">
  <thead>
    <tr>
      <th>Model</th>
      <th>Originality</th>
      <th>Validity</th>
      <th>Generalizability</th>
      <th>Comment(ko)</th>
    </tr>
  </thead>
  <tbody>
    ${reviews.map(r => `
      <tr>
        <td>${escapeHtml(r.model)}</td>
        <td style="text-align:right;">${escapeHtml(r.originality)}</td>
        <td style="text-align:right;">${escapeHtml(r.validity)}</td>
        <td style="text-align:right;">${escapeHtml(r.generalizability)}</td>
        <td>${escapeHtml(r.comment_ko || '')}</td>
      </tr>
    `).join('')}
  </tbody>
</table>
`.trim();

return [{
  final_score_5scale: finalScore,
  breakdown: reviews,
  table_markdown,
  table_html
}];
;
